export function computeFgLightnessForApcaContrast(
	bgLch: LCH,
	fgLch: LCH,
	targetContrast: number,
	epsilon = 0.1,
	maxIter = 20,
) {
	const formatSettings: FormatCSSOptions = { format: "oklch", precision: 3 };
	const bgCss = formatCSS(bgLch, formatSettings);

	const fg: LCH = { ...fgLch };

	// сохраняем относительную насыщенность
	const maxStartChroma = getOkLCHMaxChroma(fgLch);
	const chromaRatio = maxStartChroma === 0 ? 0 : fgLch.c / maxStartChroma;

	const contrastAt = (l: number) => {
		fg.l = l;

		const maxC = getOkLCHMaxChroma({ l, c: 0, h: fg.h });
		fg.c = chromaRatio * maxC;

		return Math.abs(apcaContrast(bgCss, formatCSS(fg, formatSettings)));
	};

	let lo: number, hi: number;

	if (fg.l < bgLch.l) {
		lo = 0;
		hi = bgLch.l;
	} else {
		lo = bgLch.l;
		hi = 1;
	}

	let bestL = fg.l;
	let bestDiff = Infinity;

	for (let i = 0; i < maxIter; i++) {
		const mid = (lo + hi) / 2;
		const contrast = contrastAt(mid);

		const diff = Math.abs(contrast - targetContrast);

		if (diff < bestDiff) {
			bestDiff = diff;
			bestL = mid;
		}

		if (diff <= epsilon) break;

		if (contrast > targetContrast) {
			if (mid < bgLch.l) lo = mid;
			else hi = mid;
		} else {
			if (mid < bgLch.l) hi = mid;
			else lo = mid;
		}
	}

	// финальное восстановление chroma
	const maxC = getOkLCHMaxChroma({ l: bestL, c: 0, h: fg.h });
	fg.l = bestL;
	fg.c = chromaRatio * maxC;

	return fg;
}

export function computeOpacityForApcaContrast(
	bgLch: LCH,
	fgLch: LCH,
	targetContrast: number,
	{
		epsilon = 0.1,
		maxIter = 20,
		precision = 3,
	}: {
		epsilon?: number;
		maxIter?: number;
		precision?: number;
	},
) {
	const formatSettings: FormatCSSOptions = { format: "oklch", precision: 3 };
	const bgCss = formatCSS(bgLch, formatSettings);

	const fg: LCH = { ...fgLch };

	const contrastAtOpacity = (o: number) =>
		Math.abs(
			apcaContrast(
				bgCss,
				mix(bgCss, formatCSS(fg, formatSettings), o, "oklch"),
			),
		);

	let lo = 0,
		hi = 1;

	let bestO = 1;
	let bestDiff = Infinity;

	for (let i = 0; i < maxIter; i++) {
		const mid = (lo + hi) / 2;
		const contrast = contrastAtOpacity(mid);

		const diff = Math.abs(contrast - targetContrast);

		if (diff <= bestDiff) {
			bestDiff = diff;
			bestO = mid;
		}

		if (diff <= epsilon) break;

		if (contrast > targetContrast) {
			hi = mid;
		} else {
			lo = mid;
		}
	}

	return round(bestO, precision);
}

interface Point {
	x: number;
	y: number;
}

function catmull(p0: number, p1: number, p2: number, p3: number, t: number) {
	const t2 = t * t;
	const t3 = t2 * t;

	return (
		0.5 *
		(2 * p1 +
			(-p0 + p2) * t +
			(2 * p0 - 5 * p1 + 4 * p2 - p3) * t2 +
			(-p0 + 3 * p1 - 3 * p2 + p3) * t3)
	);
}

export function catmullSplineThrough3Points(
	count: number,
	p0: number,
	p1: number,
	p2: number,
): Point[] {
	const pts: Point[] = [];

	const step = 1 / (count - 1);

	for (let i = 0; i < count; i++) {
		const x = i * step;

		let y: number;

		if (x < 0.5) {
			const t = x / 0.5;
			y = catmull(p0, p0, p1, p2, t);
		} else {
			const t = (x - 0.5) / 0.5;
			y = catmull(p0, p1, p2, p2, t);
		}

		pts.push({ x, y });
	}

	return pts;
}

class AssertionError extends Error {
	constructor(message?: string) {
		super();
		this.name = "AssertionError";
		if (message) this.message = message;
	}
}

export function assert(condition: any, msg?: string) {
	if (!condition) throw new AssertionError(msg);
}

export const getLinearEqParamK = (p1: Point, p2: Point) =>
	(p1.y - p2.y) / (p1.x - p2.x);

export const getLinearEqParamB = (p1: Point, p2: Point) =>
	p1.y - getLinearEqParamK(p1, p2) * p1.x;

export const getLinearEqParams = (p1: Point, p2: Point) => ({
	k: getLinearEqParamK(p1, p2),
	b: getLinearEqParamB(p1, p2),
});

export const getLinearEqOrdinate = (
	{ k, b }: { k: number; b: number },
	x: number,
) => k * x + b;

import type { Theme } from "@unocss/preset-wind4";
import { type Preset, presetWind4 } from "unocss";
import {
	getRippleAnimationShortcut,
	getRippleColorKeyFrames,
	getRippleScaleKeyFrames,
	getShimmerKeyFrames,
	getShimmerRules,
	getTextShimmerRules,
} from "./animation/animation";
import { getColorRules } from "./color/color";
import { getGeometryRules } from "./geometry/geometry";
import { type Options, options } from "./options";
import {
	getFocusShadows,
	getShadowShortcuts,
	getShadowsRules,
} from "./shadows/shadows";
import { getSurfaceRules, getSurfaceShortcuts } from "./surface/surface";
import {
	getTypographyRules,
	getTypographyShortcuts,
} from "./typography/typography";

const material = (opts?: Options): Preset => {
	opts ??= options;
	return {
		name: "material",
		presets: [
			presetWind4({
				dark: "class",
			}),
		],
		rules: [
			...getSurfaceRules(opts),
			...getTypographyRules(opts),
			...getGeometryRules(opts),
			...getShadowsRules(opts),
			...getColorRules(opts),
			getShimmerRules(),
			getTextShimmerRules(),
		],
		shortcuts: [
			getRippleAnimationShortcut(),
			...getTypographyShortcuts(opts),
			...getShadowShortcuts(),
			...getSurfaceShortcuts(opts),
		],
		extendTheme: (theme: Theme) => ({
			...theme,
			animation: {
				...theme.animation,
				keyframes: {
					...theme.animation?.keyframes,
					...getRippleColorKeyFrames(),
					...getRippleScaleKeyFrames(),
					...getShimmerKeyFrames(),
				},
			},
			colors: {},
			shadow: {
				...theme.shadow,
				...getFocusShadows(),
			},
			media: {
				...theme.media,
				pointer_coarse: "(pointer_coarse)",
			},
		}),
		preflights: [
			{
				getCSS: () => `:root, :host {
--spacing-size: ${options.size.spacing};
--radius: ${options.size.radius};
--text-size: ${options.size.text};
--text-weight: ${options.size.textWeight};
--transition-time: ${options.animation.transitionTime};
--min-lightness: ${options.lightness.scale.min};
--max-lightness: ${options.lightness.scale.max};
--sun-x: ${options.sun.x};
--sun-y: ${options.sun.y};
--sun-z: ${options.sun.z};
--border-width: ${options.size.borderWidth}
}`,
			},
		],
		safelist: [
			"animate-ripple-scale",
			"animate-ripple-color",
			"animate-ripple",
			"animate-text-shimmer",
			"animate-shimmer-position",
		],
	};
};

export { material as default };

