export const getDefaultSurfaceShortcut: GetStaticShortcut = () => [
	"sfc-default",
	"sfc-color-foreground-on-background-light dark:sfc-color-background-on-foreground-dark sfc-solid sfc-emphasis-high-on-high sfc-selection",
